5	
6	---------------------------------------------------------------------------------------------------
7	-- Description:
8	---------------------------------------------------------------------------------------------------
9	-- A CRC generator based on a linear-feedback shifter register. Can be used to generate CRCs to add
10	-- on TX side or to calculate CRCs to compare to received CRC on RX side.
11	--
12	-- Documentation:
13	-- https://github.com/open-logic/open-logic/blob/main/doc/base/olo_base_crc.md
14	--
15	-- Note: The link points to the documentation of the latest release. If you
16	--       use an older version, the documentation might not match the code.
17	
18	---------------------------------------------------------------------------------------------------
19	-- Libraries
20	---------------------------------------------------------------------------------------------------
21	library ieee;
22	    use ieee.std_logic_1164.all;
23	    use ieee.std_logic_misc.all;
24	    use ieee.numeric_std.all;
25	
26	library work;
27	    use work.olo_base_pkg_logic.all;
28	    use work.olo_base_pkg_math.all;
29	    use work.olo_base_pkg_string.all;
30	
31	---------------------------------------------------------------------------------------------------
32	-- Entity
33	---------------------------------------------------------------------------------------------------
34	entity olo_base_crc is
35	    generic (
36	        DataWidth_g     : positive;
37	        Polynomial_g    : std_logic_vector;  -- according to https://crccalc.com/?crc=01&method=CRC-8&datatype=hex&outtype=bin
38	        InitialValue_g  : std_logic_vector := "0";
39	        BitOrder_g      : string           := "MSB_FIRST"; -- "MSB_FIRST" or "LSB_FIRST"
40	        ByteOrder_g     : string           := "NONE";      -- "NONE", "MSB_FIRST" or "LSB_FIRST"
41	        BitflipOutput_g : boolean          := false;
42	        XorOutput_g     : std_logic_vector := "0"
43	    );
44	    port (
45	        -- Control Ports
46	        Clk              : in    std_logic;
47	        Rst              : in    std_logic;
48	        -- Input
49	        In_Data          : in    std_logic_vector(DataWidth_g-1 downto 0);
50	        In_Valid         : in    std_logic                                  := '1';
51	        In_Ready         : out   std_logic;
52	        In_Last          : in    std_logic                                  := '0';
53	        In_First         : in    std_logic                                  := '0';
54	        In_Be            : in    std_logic_vector(DataWidth_g/8-1 downto 0) := (others => '1');
55	        -- Output
56	        Out_Crc          : out   std_logic_vector(Polynomial_g'range);
57	        Out_Valid        : out   std_logic;
58	        Out_Ready        : in    std_logic                                  := '1'
59	    );
60	end entity;
61	
62	---------------------------------------------------------------------------------------------------
63	-- Architecture Declaration
64	---------------------------------------------------------------------------------------------------
65	
66	architecture rtl of olo_base_crc is
67	
68	    -- Constants
69	    constant EntityName_c          : string                                  := "olo_base_crc";
70	    constant CrcWidth_c            : natural                                 := Polynomial_g'length;
71	    constant BeMode_c              : boolean                                 := choose(DataWidth_g mod 8 = 0, true, false);
72	    constant ZeroPoly_c            : std_logic_vector(CrcWidth_c-1 downto 0) := (others => '0');
73	    -- Resized constants - required because modelsim does not compile choose() if inputs have different size, even if
74	    -- .. the input in question is not selected
75	    constant InitialValueResized_c : std_logic_vector(CrcWidth_c-1 downto 0) := std_logic_vector(resize(signed(InitialValue_g), CrcWidth_c));
76	    constant XorValueResized_c     : std_logic_vector(CrcWidth_c-1 downto 0) := std_logic_vector(resize(signed(XorOutput_g), CrcWidth_c));
77	    constant InitialValue_c        : std_logic_vector(CrcWidth_c-1 downto 0) := choose(InitialValue_g = "0", ZeroPoly_c, InitialValueResized_c);
78	    constant XorOutput_c           : std_logic_vector(CrcWidth_c-1 downto 0) := choose(XorOutput_g = "0", ZeroPoly_c, XorValueResized_c);
79	
80	    -- Signals
81	    signal LfsrReg     : std_logic_vector(CrcWidth_c-1 downto 0);
82	    signal Out_Valid_I : std_logic;
83	    signal In_Ready_I  : std_logic;
84	
85	begin
86	
87	    assert compareNoCase(BitOrder_g, "MSB_FIRST") or compareNoCase(BitOrder_g, "LSB_FIRST")
88	        report errorMessage(EntityName_c, "Illegal value for BitOrder_g")
89	        severity error;
90	    assert compareNoCase(ByteOrder_g, "NONE") or compareNoCase(ByteOrder_g, "LSB_FIRST") or compareNoCase(ByteOrder_g, "MSB_FIRST")
91	        report errorMessage(EntityName_c, "Illegal value for ByteOrder_g")
92	        severity error;
93	    assert compareNoCase(ByteOrder_g, "NONE") or DataWidth_g mod 8 = 0
94	        report errorMessage(EntityName_c, "For DataWidth_g not being a multiple of 8, only ByteOrder_g=NONE is allowed")
95	        severity error;
96	    assert InitialValue_c'length = CrcWidth_c
97	        report errorMessage(EntityName_c, "InitialValue_g must have the same length as Polynomial_g")
98	        severity error;
99	    assert XorOutput_c'length = CrcWidth_c
100	        report errorMessage(EntityName_c, "XorOutput_g must have the same length as Polynomial_g")
101	        severity error;
102	
103	    p_lfsr : process (Clk) is
104	        variable Input_v     : std_logic_vector(In_Data'range);
105	        variable Lfsr_v      : std_logic_vector(LfsrReg'range);
106	        variable InBit_v     : std_logic;
107	        variable Out_v       : std_logic_vector(CrcWidth_c-1 downto 0);
108	        variable InputHigh_v : natural;
109	        variable BePlus_v    : std_logic_vector(In_Be'range);
110	    begin
111	        if rising_edge(Clk) then
112	
113	            if (BeMode_c and In_Last = '1') then
114	                BePlus_v := std_logic_vector(unsigned(In_Be) + 1);
115	                -- synthesis translate_off
116	                assert (In_Be and BePlus_v) = zerosVector(In_Be'length)
117	                    report errorMessage(EntityName_c, "In_Be must have LSB asserted and all asserted bits must be contiguous. " &
118	                           "Trailing-Only Byte-Enable convention violated.")
119	                    severity error;
120	                -- synthesis translate_on
121	
122	                InputHigh_v := count(In_Be, '1') * 8 - 1;
123	
124	                -- Yosys cannot synthesize slices that use variable index ranges, for example:
125	                --   Input_v(InputHigh_v downto 0) := In_Data(InputHigh_v downto 0)
126	                -- Workaround: copy the data byte-by-byte inside a fixed-range loop
127	                for i in 0 to In_Be'length - 1 loop
128	                    if (i * 8 <= InputHigh_v) then
129	                        Input_v((i + 1) * 8 - 1 downto i * 8) := In_Data((i + 1) * 8 - 1 downto i * 8);
130	                    end if;
131	                end loop;
132	
133	            else
134	                Input_v     := In_Data;
135	                InputHigh_v := In_Data'high;
136	            end if;
137	
138	            -- Handle Input permutation (LFSR always processes MSB first)
139	            if compareNoCase(BitOrder_g, "MSB_FIRST") then
140	                if compareNoCase(ByteOrder_g, "LSB_FIRST") then
141	                    Input_v(InputHigh_v downto 0) := invertByteOrder(Input_v(InputHigh_v downto 0));
142	                end if;
143	            else
144	                if compareNoCase(ByteOrder_g, "MSB_FIRST") then
145	                    Input_v(InputHigh_v downto 0) := invertByteOrder(Input_v(InputHigh_v downto 0));
146	                end if;
147	                Input_v(InputHigh_v downto 0) := invertBitOrder(Input_v(InputHigh_v downto 0));
148	            end if;
149	
150	            -- Reset valid after output transmitted
151	            if Out_Valid_I = '1' and Out_Ready = '1' then
152	                Out_Valid_I <= '0';
153	            end if;
154	
155	            -- Normal Operation
156	            if In_Valid = '1' and In_Ready_I = '1' then
157	
158	                -- Report a warning when In_Be is used improperly
159	                if (BeMode_c and In_Last = '0') then
160	                    -- synthesis translate_off
161	                    assert In_Be = onesVector(In_Be'length)
162	                        report errorMessage(EntityName_c, "In_Be is de-asserted while In_Last='0'. Trailing-Only Byte-Enable convention violated.")
163	                        severity warning;
164	                    -- synthesis translate_on
165	
166	                elsif (not(BeMode_c)) then
167	                    -- synthesis translate_off
168	                    assert In_Be = onesVector(In_Be'length)
169	                        report errorMessage(EntityName_c, "In_Be is ignored when DataWidth_g is not a multiple of 8.")
170	                        severity warning;
171	                    -- synthesis translate_on
172	                end if;
173	
174	                -- First Handling
175	                if In_First = '1' then
176	                    Lfsr_v := InitialValue_c;
177	                else
178	                    Lfsr_v := LfsrReg;
179	                end if;
180	
181	                -- Iterate over all bits of In_Data, including those disabled by In_Be
182	                -- The loop bounds must be static, as variable ranges are not synthesizable
183	                for bit in In_Data'high downto 0 loop
184	
185	                    -- Only execute for the valid bits in input.
186	                    if bit <= InputHigh_v then
187	
188	                        -- Input Handling
189	                        InBit_v := Input_v(bit) xor Lfsr_v(Lfsr_v'high);
190	
191	                        -- XOR handling
192	                        Lfsr_v := Lfsr_v(Lfsr_v'high-1 downto 0) & '0';
193	                        if InBit_v = '1' then
194	                            Lfsr_v := Lfsr_v xor Polynomial_g;
195	                        end if;
196	
197	                    end if;
198	
199	                end loop;
200	
201	                -- Output Data
202	                Out_v := Lfsr_v;
203	                if BitflipOutput_g then
204	                    Out_v := invertBitOrder(Out_v);
205	                end if;
206	                Out_Crc <= Out_v xor XorOutput_c;
207	
208	                -- Last Handling
209	                if In_Last = '1' then
210	                    Lfsr_v      := InitialValue_c;
211	                    Out_Valid_I <= '1';
212	                end if;
213	                LfsrReg <= Lfsr_v;
214	            end if;
215	
216	            -- Reset
217	            if Rst = '1' then
218	                LfsrReg     <= InitialValue_c;
219	                Out_Crc     <= (others => '0');
220	                Out_Valid_I <= '0';
221	            end if;
222	
223	        end if;
224	    end process;
225	
226	    -- Combinatorial handling
227	    In_Ready_I <= Out_Ready or not Out_Valid_I;
228	
229	    -- Forward internal signal to outputs
230	    Out_Valid <= Out_Valid_I;
231	    In_Ready  <= In_Ready_I;
232	
233	end architecture;
