1	---------------------------------------------------------------------------------------------------
2	-- Copyright (c) 2025 by Oliver Bruendler
3	-- Authors: Oliver Bruendler
4	---------------------------------------------------------------------------------------------------
5	
6	---------------------------------------------------------------------------------------------------
7	-- Description:
8	---------------------------------------------------------------------------------------------------
9	-- Append a CRC to AXI4-Stream packets.
10	--
11	-- Documentation:
12	-- https://github.com/open-logic/open-logic/blob/main/doc/base/olo_base_crc_append.md
13	--
14	-- Note: The link points to the documentation of the latest release. If you
15	--       use an older version, the documentation might not match the code.
16	
17	---------------------------------------------------------------------------------------------------
18	-- Libraries
19	---------------------------------------------------------------------------------------------------
20	library ieee;
21	    use ieee.std_logic_1164.all;
22	    use ieee.std_logic_misc.all;
23	    use ieee.numeric_std.all;
24	
25	library work;
26	    use work.olo_base_pkg_logic.all;
27	    use work.olo_base_pkg_math.all;
28	    use work.olo_base_pkg_string.all;
29	
30	---------------------------------------------------------------------------------------------------
31	-- Entity
32	---------------------------------------------------------------------------------------------------
33	entity olo_base_crc_append is
34	    generic (
35	        DataWidth_g        : positive;
36	        CrcPolynomial_g    : std_logic_vector;                -- See olo_base_crc
37	        CrcInitialValue_g  : std_logic_vector := "0";         -- See olo_base_crc
38	        CrcBitOrder_g      : string           := "MSB_FIRST"; -- See olo_base_crc
39	        CrcByteOrder_g     : string           := "NONE";      -- See olo_base_crc
40	        CrcBitflipOutput_g : boolean          := false;       -- See olo_base_crc
41	        CrcXorOutput_g     : std_logic_vector := "0"          -- See olo_base_crc
42	    );
43	    port (
44	        -- Control Ports
45	        Clk              : in    std_logic;
46	        Rst              : in    std_logic;
47	        -- Input
48	        In_Data          : in    std_logic_vector(DataWidth_g-1 downto 0);
49	        In_Valid         : in    std_logic := '1';
50	        In_Ready         : out   std_logic;
51	        In_Last          : in    std_logic;
52	        -- Output
53	        Out_Data         : out   std_logic_vector(DataWidth_g-1 downto 0);
54	        Out_Valid        : out   std_logic;
55	        Out_Ready        : in    std_logic := '1';
56	        Out_Last         : out   std_logic
57	    );
58	end entity;
59	
60	---------------------------------------------------------------------------------------------------
61	-- Architecture Declaration
62	---------------------------------------------------------------------------------------------------
63	
64	architecture rtl of olo_base_crc_append is
65	
66	    -- *** Constants ***
67	    constant EntityName_c : string := "olo_base_crc_append";
68	
69	    -- *** Types ***
70	    type State_t is (Data_s, Crc_s);
71	
72	    -- *** Two Process Method ***
73	    type TwoProcess_r is record
74	        State : State_t;
75	    end record;
76	
77	    signal r, r_next : TwoProcess_r;
78	
79	    -- *** Instantiation Signals ***
80	    signal Crc_Valid : std_logic;
81	    signal Crc_Ready : std_logic;
82	    signal Crc_Crc   : std_logic_vector(CrcPolynomial_g'length-1 downto 0);
83	    signal Pl_Valid  : std_logic;
84	    signal Pl_Data   : std_logic_vector(DataWidth_g-1 downto 0);
85	    signal Pl_Last   : std_logic;
86	    signal Pl_Ready  : std_logic;
87	    signal In_Beat   : std_logic;
88	
89	begin
90	
91	    -- *** Assertions ***
92	    assert CrcPolynomial_g'length <= DataWidth_g
93	        report errorMessage(EntityName_c, "Polynomial_g must be smaller or equal width than DataWidth_g")
94	        severity error;
95	
96	    -- *** Combinatorial Process ***
97	    p_comb : process (all) is
98	        variable v : TwoProcess_r;
99	    begin
100	        -- *** Hold Variables Stable ***
101	        v := r;
102	
103	        -- *** FSM ***
104	        In_Ready  <= '0';
105	        Crc_Ready <= '0';
106	        Pl_Data   <= (others => 'X');
107	        Pl_Valid  <= '0';
108	        Pl_Last   <= '0';
109	        In_Beat   <= '0';
110	
111	        case r.State is
112	            when Data_s =>
113	                Pl_Data  <= In_Data;
114	                Pl_Valid <= In_Valid;
115	                In_Ready <= Pl_Ready;
116	                In_Beat  <= In_Valid and Pl_Ready;
117	
118	                if In_Valid = '1' and Pl_Ready = '1' and In_Last = '1' then
119	                    v.State := Crc_s;
120	                end if;
121	
122	            when Crc_s =>
123	                Pl_Data                <= (others => '0');
124	                Pl_Data(Crc_Crc'range) <= Crc_Crc;
