        i_fifo : entity work.olo_base_fifo_packet
            generic map (
                Width_g             => DataWidth_g,
                Depth_g             => FifoDepth_g,
                FeatureSet_g        => "DROP_ONLY",
                RamStyle_g          => FifoRamStyle_g,
                RamBehavior_g       => FifoRamBehavior_g
            )
            port map (
                Clk           => Clk,
                Rst           => Rst,
                -- Input Data
                In_Valid      => Pl_Valid,
                In_Ready      => Pl_Ready,
                In_Data       => r.Data,
                In_Last       => In_Last,
                In_Drop       => Pl_CrcErr,
                Out_Valid     => Out_Valid,
                Out_Ready     => Out_Ready,
                Out_Data      => Out_Data,
                Out_Last      => Out_Last
            );

        Out_CrcErr <= Pl_CrcErr;
    end generate;

    g_flag : if compareNoCase(Mode_g, "flag") generate
        signal InData  : std_logic_vector(DataWidth_g+1 downto 0);
        signal OutData : std_logic_vector(DataWidth_g+1 downto 0);
    begin
        -- Input Assembly
        InData <= Pl_CrcErr & In_Last & r.Data;

        -- Instantiation
        i_pl : entity work.olo_base_pl_stage
            generic map (
                Width_g     => DataWidth_g+2
            )
            port map (
                Clk         => Clk,
                Rst         => Rst,
                In_Valid    => Pl_Valid,
                In_Ready    => Pl_Ready,
                In_Data     => InData,
                Out_Valid   => Out_Valid,
                Out_Ready   => Out_Ready,
                Out_Data    => OutData
            );

        -- Output Disassembly
        Out_CrcErr <= OutData(OutData'high);
        Out_Last   <= OutData(OutData'high-1);
        Out_Data   <= OutData(DataWidth_g-1 downto 0);
    end generate;

end architecture;

