158	        variable Last_v     : std_logic                                := '0';
159	        variable CrcError_v : std_logic_vector(0 downto 0)             := "0";
160	        variable XorMask_v  : std_logic_vector(DataWidth_g-1 downto 0) := (others => '0');
161	    begin
162	
163	        -- For DROP, errors are not even shown
164	        if error_word >= 0 then
