226	    p_control : process is
227	        variable ErrorCounterStart_v : integer;
228	    begin
229	        test_runner_setup(runner, runner_cfg);
230	
231	        while test_suite loop
232	
233	            InDelay_v  := 0 ns;
234	            OutDelay_v := 0 ns;
