237	            wait until rising_edge(Clk);
238	            Rst <= '1';
239	            wait for ClkPeriod_c;
240	            wait until rising_edge(Clk);
241	            Rst <= '0';
242	            wait until rising_edge(Clk);
243	
244	            -- *** Correct Cases ***
245	
246	            -- State after reset
247	            if run("Reset") then
248	                check_equal(Out_Valid, '0', "Out_Valid");
249	                check_equal(ErrorCounter, 0);
250	            end if;
251	
252	            -- One packet with slow data
253	            if run("1Pkt-2Beat-Slow") then
254	                InDelay_v := 3*ClkPeriod_c;
255	                pushPacket(net, 2);
256	                checkResponse(net, 2);
257	                check_equal(ErrorCounter, 0);
258	            end if;
259	
260	            -- One packket with fast data
261	            if run("1Pkt-3Beat-Fast") then
262	                pushPacket(net, 3);
263	                checkResponse(net, 3);
264	                check_equal(ErrorCounter, 0);
265	            end if;
266	
267	            -- One packket with packpressure
268	            if run("1Pkt-4Beat-BackPress") then
269	                OutDelay_v := 3*ClkPeriod_c;
270	                pushPacket(net, 4);
271	                checkResponse(net, 4);
272	                check_equal(ErrorCounter, 0);
273	            end if;
274	
275	            -- Two packket with fast data
276	            if run("3Pkt-Fast") then
277	                pushPacket(net, 3);
278	                pushPacket(net, 4);
279	                pushPacket(net, 3);
280	                checkResponse(net, 3);
281	                checkResponse(net, 4);
282	                checkResponse(net, 3);
283	                check_equal(ErrorCounter, 0);
284	            end if;
285	
286	            -- Two packket with Back Pressure
287	            if run("2Pkt-BackPress") then
288	                OutDelay_v := 3*ClkPeriod_c;
289	                pushPacket(net, 4);
290	                pushPacket(net, 3);
291	                checkResponse(net, 4);
292	                checkResponse(net, 3);
293	                check_equal(ErrorCounter, 0);
294	            end if;
295	
296	            -- *** Error Cases ***
297	
298	            -- Two packket with fast data, error in middle data
299	            if run("3Pkt-Fast-Error-Data") then
300	
301	                for i in 0 to 3 loop
302	                    ErrorCounterStart_v := ErrorCounter;
303	                    pushPacket(net, 3);
304	                    pushPacket(net, 4, error_word => i);
305	                    pushPacket(net, 3);
306	                    checkResponse(net, 3);
307	                    checkResponse(net, 4, error_word => i);
308	                    checkResponse(net, 3);
309	                    check_equal(ErrorCounter, ErrorCounterStart_v+1);
310	                end loop;
311	
312	            end if;
313	
314	            -- Two packket with fast data, error in middle crc
315	            if run("3Pkt-Fast-Error-Crc") then
316	                ErrorCounterStart_v := ErrorCounter;
317	                pushPacket(net, 3);
318	                pushPacket(net, 4, error_word => 4);
319	                pushPacket(net, 3);
320	                checkResponse(net, 3);
321	                checkResponse(net, 4, error_word => 4);
322	                checkResponse(net, 3);
323	                check_equal(ErrorCounter, ErrorCounterStart_v+1);
324	            end if;
325	
326	            -- Two packket with fast data, error in middle data
327	            if run("3Pkt-Backpressure-Error-Data") then
328	                OutDelay_v          := 10*ClkPeriod_c;
329	                ErrorCounterStart_v := ErrorCounter;
330	
331	                -- Input Loop
332	                for i in 0 to 3 loop
333	                    pushPacket(net, 3);
334	                    pushPacket(net, 4, error_word => i);
335	                    pushPacket(net, 3);
336	                end loop;
337	
338	                -- check loop
339	                for i in 0 to 3 loop
340	                    checkResponse(net, 3);
341	                    checkResponse(net, 4, error_word => i);
342	                    checkResponse(net, 3);
343	                end loop;
344	
345	                check_equal(ErrorCounter, ErrorcounterStart_v+4);
346	            end if;
347	
348	            -- Single Data Word Error in Data
349	            if run("3Pkt-Single-Error-Data") then
350	                ErrorCounterStart_v := ErrorCounter;
351	                pushPacket(net, 1);
352	                pushPacket(net, 1, error_word => 0);
353	                pushPacket(net, 1);
354	                checkResponse(net, 1);
355	                checkResponse(net, 1, error_word => 0);
356	                checkResponse(net, 1);
357	                check_equal(ErrorCounter, ErrorCounterStart_v+1);
358	            end if;
359	
360	            if run("3Pkt-Single-Error-Crc") then
361	                ErrorCounterStart_v := ErrorCounter;
362	                pushPacket(net, 1);
363	                pushPacket(net, 1, error_word => 1);
364	                pushPacket(net, 1);
365	                checkResponse(net, 1);
366	                checkResponse(net, 1, error_word => 1);
367	                checkResponse(net, 1);
368	                check_equal(ErrorCounter, ErrorCounterStart_v+1);
369	            end if;
370	
371	            wait for 1 us;
372	            wait_until_idle(net, as_sync(AxisMaster_c));
373	            wait_until_idle(net, as_sync(AxisSlave_c));
374	
375	        end loop;
376	
377	        -- TB done
378	        test_runner_cleanup(runner);
379	    end process;
380	
381	    -----------------------------------------------------------------------------------------------
382	    -- Clock
383	    -----------------------------------------------------------------------------------------------
384	    Clk <= not Clk after 0.5 * ClkPeriod_c;
385	
386	    -----------------------------------------------------------------------------------------------
387	    -- DUT
388	    -----------------------------------------------------------------------------------------------
389	    i_dut : entity olo.olo_base_crc_check
390	        generic map (
391	            DataWidth_g        => DataWidth_g,
392	            FifoDepth_g        => FifoDepth_c,
393	            Mode_g             => Mode_g,
394	            CrcPolynomial_g    => getPolynomial(CrcWidth_g),
395	            CrcInitialValue_g  => "0",
396	            CrcBitOrder_g      => "MSB_FIRST",
397	            CrcByteOrder_g     => "NONE",
398	            CrcBitflipOutput_g => false,
399	            CrcXorOutput_g     => "0"
400	        )
401	        port map (
402	            Clk        => Clk,
403	            Rst        => Rst,
404	            In_Data    => In_Data,
405	            In_Valid   => In_Valid,
406	            In_Ready   => In_Ready,
407	            In_Last    => In_Last,
408	            Out_Data   => Out_Data,
409	            Out_Valid  => Out_Valid,
410	            Out_Ready  => Out_Ready,
411	            Out_Last   => Out_Last,
412	            Out_CrcErr => Out_CrcErr
413	        );
414	
415	    -----------------------------------------------------------------------------------------------
416	    -- Verification Components
417	    -----------------------------------------------------------------------------------------------
418	    p_count : process (Clk) is
419	        variable CrcErrLast_v : std_logic := '0';
420	    begin
421	        if rising_edge(Clk) then
422	            -- Single cycle errors for DROP
423	            if Mode_g = "DROP" and Out_CrcErr = '1' then
424	                ErrorCounter <= ErrorCounter + 1;
425	            end if;
426	            -- Might be longer for FLAG
427	            if Mode_g = "FLAG" and Out_CrcErr = '1'  and CrcErrLast_v = '0' then
428	                ErrorCounter <= ErrorCounter + 1;
429	            end if;
430	
431	            CrcErrLast_v := Out_CrcErr;
432	        end if;
433	    end process;
434	
435	    vc_stimuli : entity vunit_lib.axi_stream_master
436	        generic map (
437	            Master => AxisMaster_c
438	        )
439	        port map (
440	            AClk      => Clk,
441	            TValid    => In_Valid,
442	            TReady    => In_Ready,
443	            TData     => In_Data,
444	            TLast     => In_Last
445	        );
446	
447	    b_resp : block is
448	        signal Out_User : std_logic;
449	    begin
450	        Out_User <= Out_CrcErr when Mode_g = "FLAG" else '0';
451	
452	        vc_response : entity vunit_lib.axi_stream_slave
453	            generic map (
454	                Slave => AxisSlave_c
455	            )
456	            port map (
457	                AClk     => Clk,
458	                TValid   => Out_Valid,
459	                TReady   => Out_Ready,
460	                TData    => Out_Data,
461	                TLast    => Out_Last,
462	                TUser(0) => Out_User
463	            );
464	
465	    end block;
466	
467	end architecture;
